ALTER TABLE `pharmaceuticals_ecm`.`pharmacovigilance`.`sae_report` ADD CONSTRAINT `fk_pharmacovigilance_sae_report_pv_product_id` FOREIGN KEY (`pv_product_id`) REFERENCES `pharmaceuticals_ecm`.`pharmacovigilance`.`pv_product`(`pv_product_id`);
