ALTER TABLE `pharmaceuticals_ecm`.`pharmacovigilance`.`sae_report` ADD CONSTRAINT `fk_pharmacovigilance_sae_report_susar_id` FOREIGN KEY (`susar_id`) REFERENCES `pharmaceuticals_ecm`.`pharmacovigilance`.`susar`(`susar_id`);
ALTER TABLE `pharmaceuticals_ecm`.`pharmacovigilance`.`pv_submission` ADD CONSTRAINT `fk_pharmacovigilance_pv_submission_original_submission_pv_submission_id` FOREIGN KEY (`original_submission_pv_submission_id`) REFERENCES `pharmaceuticals_ecm`.`pharmacovigilance`.`pv_submission`(`pv_submission_id`);
